mapper.update:
update worker
name=#{name}, phone=#{phone}, gender=#{gender}, avatar=#{avatar}, skill_desc=#{skillDesc}, service_status=#{serviceStatus}, latitude=#{latitude}, longitude=#{longitude}, rating=#{rating}, status=#{status}, create_time=#{createTime}, update_time=#{updateTime},
where id=#{id}

mapper.select:
select w.*, case w.service_status when 0 then '休息中' when 1 then '待接单' when 2 then '服务中' end as serviceStatusName, (select count(*) from service_order so where so.worker_id=w.id ) as orderCount from worker w
name like concat('%',#{name},'%')
and status=#{status}
